import{_ as o,o as d,c as t,a3 as a}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Database architecture","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Database architecture | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/database"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Database architecture | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/database"}]]},"headers":[],"relativePath":"developer-guide/database.md","filePath":"developer-guide/database.md","lastUpdated":1784403917000}'),c={name:"developer-guide/database.md"};function s(n,e,i,r,l,p){return d(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="database-architecture" tabindex="-1">Database architecture <a class="header-anchor" href="#database-architecture" aria-label="Permalink to &quot;Database architecture&quot;">‚Äã</a></h1><p>Single shared database. Catalog tables are <strong>central-only</strong> (no <code>tenant_id</code>). Workspace-scoped rows use <code>tenant_id</code> FKs.</p><h2 id="entity-overview" tabindex="-1">Entity overview <a class="header-anchor" href="#entity-overview" aria-label="Permalink to &quot;Entity overview&quot;">‚Äã</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>central_users          tenants ‚îÄ‚îÄhas‚îÄ‚îÄ‚ñ∫ workspace_module_subscriptions ‚îÄ‚îÄ‚ñ∫ modules</span></span>\n<span class="line"><span>                              ‚îÇ                ‚îÇ</span></span>\n<span class="line"><span>                              ‚îÇ                ‚îî‚îÄ‚îÄ workspace_module_subscription_history</span></span>\n<span class="line"><span>                              ‚îÇ</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ tenant_settings</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ billing profile columns (anchor, cycle, proration, next_billing_at)</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ invoices ‚îÄ‚îÄ‚ñ∫ invoice_items</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ payments ‚îÄ‚îÄ‚ñ∫ payment_transactions</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ payment_methods, billing_addresses</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ impersonation_sessions (central_user_id)</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ (Cashier) subscriptions ‚îÄ‚îÄ‚ñ∫ subscription_items</span></span>\n<span class="line"><span>                              ‚îú‚îÄ‚îÄ stripe_id / pm_type / pm_last_four (Billable / Stripe)</span></span>\n<span class="line"><span>                              ‚îî‚îÄ‚îÄ tenant_gateway_customers (provider-neutral customer_reference)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>modules ‚îÄ‚îÄ‚ñ∫ module_categories</span></span>\n<span class="line"><span>modules ‚îÄ‚îÄ‚ñ∫ module_dependencies (depends_on_module_id)</span></span>\n<span class="line"><span>payment_gateways ‚îÄ‚îÄ‚ñ∫ gateway_logs, webhook_logs, payment_attempts, tenant_gateway_customers</span></span>\n<span class="line"><span>system_settings (key/value ‚Äî Central Application settings; see Settings section)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>lead_stages / leads / lead_notes / lead_follow_ups / lead_activities</span></span>\n<span class="line"><span>lead_assignment_histories</span></span>\n<span class="line"><span>  (tenant-scoped CRM ‚Äî Leads module)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>tasks / task_notes / task_activities</span></span>\n<span class="line"><span>  (tenant-scoped work items ‚Äî Tasks module)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>communication_templates</span></span>\n<span class="line"><span>  (tenant-scoped plain-text templates ‚Äî Communication Templates module)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>notifications</span></span>\n<span class="line"><span>  (Laravel database notifications ‚Äî polymorphic notifiable)</span></span></code></pre></div><p><code>tenants</code> is the Cashier <strong>billable</strong> model. Cashier&#39;s <code>subscriptions</code>/<code>subscription_items</code> are the Stripe mirror. <strong><code>workspace_module_subscriptions</code> is the business source of truth</strong> for licensing. <strong><code>invoices</code> / <code>payments</code> are the financial ledger SoT.</strong></p><p>Plans, plan pivots, limit definitions, feature catalogs, and <code>tenant_subscriptions</code> have been <strong>removed</strong>.</p><h2 id="leads-module-tables" tabindex="-1">Leads module tables <a class="header-anchor" href="#leads-module-tables" aria-label="Permalink to &quot;Leads module tables&quot;">‚Äã</a></h2><h3 id="lead-stages" tabindex="-1"><code>lead_stages</code> <a class="header-anchor" href="#lead-stages" aria-label="Permalink to &quot;`lead_stages`&quot;">‚Äã</a></h3><p>Per-workspace pipeline: <code>tenant_id</code>, <code>uuid</code>, <code>name</code>, <code>slug</code>, <code>color</code>, <code>sort_order</code>, <code>is_won</code>, <code>is_lost</code>, <code>is_default</code>, soft deletes. Seeded New ‚Üí Contacted ‚Üí Qualified ‚Üí Proposal ‚Üí Negotiation ‚Üí Won / Lost.</p><h3 id="leads" tabindex="-1"><code>leads</code> <a class="header-anchor" href="#leads" aria-label="Permalink to &quot;`leads`&quot;">‚Äã</a></h3><p><code>tenant_id</code>, <code>uuid</code>, <code>name</code>, contact fields, <code>stage_id</code>, <code>status</code> (<code>active</code>|<code>waiting</code>|<code>on_hold</code>|<code>closed</code>|<code>archived</code>), <code>priority</code> (<code>low</code>|<code>medium</code>|<code>high</code>|<code>urgent</code>), <code>assigned_to</code>, <code>lead_value</code> (renamed from <code>estimated_value</code>), <code>last_contacted_at</code>, <code>next_follow_up_at</code>, <code>converted_at</code>, <code>conversion_meta</code> (JSON), soft deletes. Status is <strong>independent</strong> of stage. Spatie activity log name <code>leads</code>.</p><h3 id="lead-notes-lead-follow-ups-lead-activities" tabindex="-1"><code>lead_notes</code> / <code>lead_follow_ups</code> / <code>lead_activities</code> <a class="header-anchor" href="#lead-notes-lead-follow-ups-lead-activities" aria-label="Permalink to &quot;`lead_notes` / `lead_follow_ups` / `lead_activities`&quot;">‚Äã</a></h3><p>Notes (author + body), follow-ups (due/complete/status), and CRM timeline (<code>type</code>, <code>description</code>, <code>properties</code> JSON).</p><h3 id="lead-assignment-histories" tabindex="-1"><code>lead_assignment_histories</code> <a class="header-anchor" href="#lead-assignment-histories" aria-label="Permalink to &quot;`lead_assignment_histories`&quot;">‚Äã</a></h3><p><code>tenant_id</code>, <code>lead_id</code>, <code>old_user_id</code>, <code>new_user_id</code>, <code>changed_by</code>, <code>reason</code>, timestamps. Records assignee changes.</p><h2 id="tasks-module-tables" tabindex="-1">Tasks module tables <a class="header-anchor" href="#tasks-module-tables" aria-label="Permalink to &quot;Tasks module tables&quot;">‚Äã</a></h2><h3 id="tasks" tabindex="-1"><code>tasks</code> <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;`tasks`&quot;">‚Äã</a></h3><p><code>tenant_id</code>, <code>uuid</code>, <code>title</code>, <code>description</code>, <code>status</code> (<code>open</code>|<code>in_progress</code>|<code>waiting</code>|<code>completed</code>|<code>cancelled</code>), <code>priority</code> (<code>low</code>|<code>medium</code>|<code>high</code>|<code>urgent</code>), <code>due_at</code>, <code>assigned_to</code>, <code>created_by</code>, <code>completed_at</code>, soft deletes. Spatie activity log name <code>tasks</code>. UI labels <code>open</code> as <strong>To Do</strong>.</p><h3 id="task-notes-task-activities" tabindex="-1"><code>task_notes</code> / <code>task_activities</code> <a class="header-anchor" href="#task-notes-task-activities" aria-label="Permalink to &quot;`task_notes` / `task_activities`&quot;">‚Äã</a></h3><p>Notes / comments (author + body) and task timeline (<code>type</code>, <code>description</code>, <code>properties</code> JSON).</p><h2 id="communication-templates-module-tables" tabindex="-1">Communication Templates module tables <a class="header-anchor" href="#communication-templates-module-tables" aria-label="Permalink to &quot;Communication Templates module tables&quot;">‚Äã</a></h2><h3 id="communication-templates" tabindex="-1"><code>communication_templates</code> <a class="header-anchor" href="#communication-templates" aria-label="Permalink to &quot;`communication_templates`&quot;">‚Äã</a></h3><p><code>tenant_id</code>, <code>uuid</code> (route key), <code>name</code>, <code>context</code> (e.g. <code>leads</code>), <code>channel</code> (MVP: <code>whatsapp</code>), <code>category</code> (nullable), <code>body</code> (plain text), <code>is_active</code>, <code>created_by</code>, <code>updated_by</code>, <code>last_used_at</code>, soft deletes. Unique name per tenant+context+channel among non-deleted rows. Placeholders are not stored as rows ‚Äî they come from the in-code registry.</p><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">‚Äã</a></h2><h3 id="notifications-1" tabindex="-1"><code>notifications</code> <a class="header-anchor" href="#notifications-1" aria-label="Permalink to &quot;`notifications`&quot;">‚Äã</a></h3><p>Laravel standard table: UUID <code>id</code> (stable public notification id), <code>type</code>, morphs <code>notifiable</code>, <code>data</code> (JSON envelope <code>schema_version: 1</code>), <code>read_at</code>, timestamps.</p><p>Indexes: morph index plus composites <code>(notifiable_type, notifiable_id, read_at)</code> and <code>(notifiable_type, notifiable_id, created_at)</code> for unread/list queries.</p><p>Retention: <code>php artisan notifications:prune --days=90</code> (scheduled weekly) deletes <strong>read</strong> rows only. See <a href="/developer-guide/notification-architecture-contract">notification-architecture-contract</a>.</p><h2 id="table-dictionary-licensing-catalog" tabindex="-1">Table dictionary (licensing &amp; catalog) <a class="header-anchor" href="#table-dictionary-licensing-catalog" aria-label="Permalink to &quot;Table dictionary (licensing &amp; catalog)&quot;">‚Äã</a></h2><h3 id="module-categories" tabindex="-1"><code>module_categories</code> <a class="header-anchor" href="#module-categories" aria-label="Permalink to &quot;`module_categories`&quot;">‚Äã</a></h3><p><code>name</code>, <code>slug</code> (unique), <code>description</code>, <code>sort_order</code>, <code>is_active</code>.</p><h3 id="modules" tabindex="-1"><code>modules</code> <a class="header-anchor" href="#modules" aria-label="Permalink to &quot;`modules`&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>Unique public id</td></tr><tr><td><code>name</code>, <code>slug</code> (unique), <code>description</code>, <code>icon</code></td><td></td></tr><tr><td><code>category_id</code></td><td>FK <code>module_categories</code>, nullable</td></tr><tr><td><code>monthly_price</code>, <code>yearly_price</code>, <code>currency</code>, <code>setup_fee</code></td><td>Catalog amounts; default CRM modules are <code>0</code>. No provider IDs on modules</td></tr><tr><td><code>trial_days</code>, <code>version</code>, <code>status</code></td><td><code>draft</code> | <code>published</code> | <code>deprecated</code></td></tr><tr><td><code>is_default_included</code></td><td>Auto-install on workspace create</td></tr><tr><td><code>is_billable</code></td><td>Whether the module can be charged when platform-managed</td></tr><tr><td><code>sort_order</code>, <code>is_active</code></td><td></td></tr><tr><td>soft deletes</td><td></td></tr></tbody></table><p>Default-included catalog modules today: <strong>Leads</strong>, <strong>Tasks</strong>, <strong>Communication Templates</strong> (<code>is_default_included=true</code>, <code>is_billable=false</code>). Production receives new default modules via <strong>data migrations</strong> (<code>DefaultModuleRegistrar</code>), not seeders. Modules are pure licensing products ‚Äî they do not store permission lists. User authorization uses Spatie Roles &amp; Permissions separately.</p><h3 id="payment-gateway-module-prices" tabindex="-1"><code>payment_gateway_module_prices</code> <a class="header-anchor" href="#payment-gateway-module-prices" aria-label="Permalink to &quot;`payment_gateway_module_prices`&quot;">‚Äã</a></h3><p>Per-gateway catalog mapping (provider-agnostic price references):</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>payment_gateway_id</code>, <code>module_id</code>, <code>billing_cycle</code></td><td>Unique triple (<code>monthly</code> | <code>yearly</code>)</td></tr><tr><td><code>gateway_product_reference</code></td><td>e.g. Stripe <code>prod_‚Ä¶</code>, PayPal plan id ‚Äî nullable</td></tr><tr><td><code>gateway_price_reference</code></td><td>e.g. Stripe <code>price_‚Ä¶</code> ‚Äî required for checkout when gateway <code>requiresProductMapping()</code></td></tr><tr><td><code>gateway_metadata</code></td><td>JSON bag for driver-specific extras</td></tr></tbody></table><h3 id="module-dependencies" tabindex="-1"><code>module_dependencies</code> <a class="header-anchor" href="#module-dependencies" aria-label="Permalink to &quot;`module_dependencies`&quot;">‚Äã</a></h3><p><code>(module_id, depends_on_module_id)</code> unique. Optional flag <code>is_optional</code>. Enforced on marketplace install.</p><h3 id="workspace-module-subscriptions" tabindex="-1"><code>workspace_module_subscriptions</code> <a class="header-anchor" href="#workspace-module-subscriptions" aria-label="Permalink to &quot;`workspace_module_subscriptions`&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>tenant_id</code>, <code>module_id</code></td><td>Unique pair</td></tr><tr><td><code>status</code></td><td><code>pending</code> | <code>trial</code> | <code>active</code> | <code>expired</code> | <code>cancelled</code> | <code>suspended</code></td></tr><tr><td><code>source</code></td><td><code>included</code> | <code>purchased</code> | <code>trial</code></td></tr><tr><td><code>billing_cycle</code>, <code>price</code>, <code>currency</code>, <code>is_billable</code></td><td>Snapshot for billing</td></tr><tr><td>period timestamps</td><td><code>trial_*</code>, <code>starts_at</code>, <code>ends_at</code>, <code>renews_at</code>, <code>cancelled_at</code></td></tr><tr><td><code>provider</code>, <code>provider_subscription_id</code></td><td>Gateway-facing refs</td></tr><tr><td><code>payment_gateway_id</code></td><td>FK to <code>payment_gateways</code> (nullable) ‚Äî which driver owns renewals</td></tr><tr><td>soft deletes</td><td></td></tr></tbody></table><h3 id="workspace-module-subscription-history" tabindex="-1"><code>workspace_module_subscription_history</code> <a class="header-anchor" href="#workspace-module-subscription-history" aria-label="Permalink to &quot;`workspace_module_subscription_history`&quot;">‚Äã</a></h3><p>Append-only events: <code>module_installed</code>, <code>module_purchase_pending</code>, <code>module_activated</code>, <code>module_cancelled</code>, <code>module_suspended</code>, etc.</p><h3 id="tenants-billing-profile-columns" tabindex="-1"><code>tenants</code> billing profile columns <a class="header-anchor" href="#tenants-billing-profile-columns" aria-label="Permalink to &quot;`tenants` billing profile columns&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>billing_anchor_day</code></td><td>1‚Äì28</td></tr><tr><td><code>billing_cycle</code></td><td>Workspace default (<code>monthly</code> / <code>yearly</code>)</td></tr><tr><td><code>proration_mode</code></td><td><code>prorated</code> | <code>free_until_next</code> | <code>none</code></td></tr><tr><td><code>next_billing_at</code></td><td>Next consolidated invoice run</td></tr></tbody></table><p>Workspace profile columns include <code>company_name</code>, <code>workspace_name</code>, <code>slug</code>, <code>email</code>, <code>phone</code>, <code>logo_path</code>, <code>notes</code>, <code>timezone</code>, <code>currency</code>, <code>country</code>, <code>locale</code>. There is <strong>no</strong> <code>owner_id</code> or <code>address</code> column.</p><h2 id="table-dictionary-financial-ledger" tabindex="-1">Table dictionary (financial ledger) <a class="header-anchor" href="#table-dictionary-financial-ledger" aria-label="Permalink to &quot;Table dictionary (financial ledger)&quot;">‚Äã</a></h2><h3 id="payment-gateways" tabindex="-1"><code>payment_gateways</code> <a class="header-anchor" href="#payment-gateways" aria-label="Permalink to &quot;`payment_gateways`&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>code</code> (unique), <code>name</code>, <code>driver</code></td><td>Driver class FQCN</td></tr><tr><td><code>is_active</code>, <code>is_default</code>, <code>mode</code></td><td><code>sandbox</code> | <code>live</code></td></tr><tr><td><code>config</code></td><td>Encrypted array (credentials); never expose secrets via API</td></tr><tr><td><code>supported_currencies</code>, <code>capabilities</code></td><td>Cached/display; drivers remain source of truth</td></tr><tr><td><code>webhook_status</code>, <code>webhook_last_received_at</code></td><td>Ingress health</td></tr><tr><td><code>last_tested_at</code>, <code>last_test_status</code>, <code>last_test_message</code></td><td>Connection probe</td></tr><tr><td><code>sort_order</code></td><td></td></tr></tbody></table><p>Seeded: <code>manual</code>, <code>stripe</code>.</p><h3 id="payment-methods" tabindex="-1"><code>payment_methods</code> <a class="header-anchor" href="#payment-methods" aria-label="Permalink to &quot;`payment_methods`&quot;">‚Äã</a></h3><p>Workspace preferred / saved methods: <code>tenant_id</code>, <code>payment_gateway_id</code>, <code>type</code>, <code>brand</code>, <code>last_four</code>, encrypted <code>token</code>, <code>is_default</code>.</p><h3 id="payment-attempts" tabindex="-1"><code>payment_attempts</code> <a class="header-anchor" href="#payment-attempts" aria-label="Permalink to &quot;`payment_attempts`&quot;">‚Äã</a></h3><p>Gateway-agnostic checkout/charge attempts linked to optional <code>payment_id</code> / <code>invoice_id</code>.</p><h3 id="gateway-logs-webhook-logs" tabindex="-1"><code>gateway_logs</code> / <code>webhook_logs</code> <a class="header-anchor" href="#gateway-logs-webhook-logs" aria-label="Permalink to &quot;`gateway_logs` / `webhook_logs`&quot;">‚Äã</a></h3><p>Operational admin/driver events and inbound webhook audit trail.</p><h3 id="billing-addresses" tabindex="-1"><code>billing_addresses</code> <a class="header-anchor" href="#billing-addresses" aria-label="Permalink to &quot;`billing_addresses`&quot;">‚Äã</a></h3><p>Workspace billing addresses: <code>tenant_id</code>, address lines, <code>is_default</code>.</p><h3 id="taxes-coupons-refunds-credit-notes" tabindex="-1"><code>taxes</code>, <code>coupons</code>, <code>refunds</code>, <code>credit_notes</code> <a class="header-anchor" href="#taxes-coupons-refunds-credit-notes" aria-label="Permalink to &quot;`taxes`, `coupons`, `refunds`, `credit_notes`&quot;">‚Äã</a></h3><p>Supporting ledger tables for future tax/discount/refund flows. Not exposed in Central v1 read APIs yet.</p><h3 id="invoices" tabindex="-1"><code>invoices</code> <a class="header-anchor" href="#invoices" aria-label="Permalink to &quot;`invoices`&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>uuid</code>, <code>number</code></td><td>Unique identifiers</td></tr><tr><td><code>tenant_id</code></td><td>FK <code>tenants</code></td></tr><tr><td><code>status</code></td><td><code>draft</code> | <code>open</code> | <code>paid</code> | <code>void</code> | ‚Ä¶</td></tr><tr><td><code>subtotal</code>, <code>tax_total</code>, <code>discount_total</code>, <code>total</code>, <code>amount_paid</code>, <code>amount_due</code></td><td></td></tr><tr><td><code>payment_gateway_id</code>, <code>coupon_id</code>, <code>billing_address_id</code></td><td>Nullable FKs</td></tr><tr><td><code>issue_date</code>, <code>due_date</code>, <code>paid_at</code></td><td></td></tr><tr><td>soft deletes</td><td></td></tr></tbody></table><h3 id="invoice-items" tabindex="-1"><code>invoice_items</code> <a class="header-anchor" href="#invoice-items" aria-label="Permalink to &quot;`invoice_items`&quot;">‚Äã</a></h3><p>Line items: <code>invoice_id</code>, <code>type</code> (<code>module</code> | <code>proration</code> | ‚Ä¶), optional <code>module_id</code> + <code>workspace_module_subscription_id</code>, <code>description</code>, <code>quantity</code>, <code>unit_amount</code>, <code>total</code>, <code>meta</code>.</p><h3 id="payments" tabindex="-1"><code>payments</code> <a class="header-anchor" href="#payments" aria-label="Permalink to &quot;`payments`&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>Unique public id</td></tr><tr><td><code>tenant_id</code>, <code>invoice_id</code></td><td></td></tr><tr><td><code>payment_gateway_id</code>, <code>payment_method_id</code></td><td></td></tr><tr><td><code>amount</code>, <code>tax</code>, <code>currency</code>, <code>status</code></td><td><code>pending</code> | <code>succeeded</code> | <code>failed</code> | ‚Ä¶</td></tr><tr><td><code>transaction_id</code>, <code>reference</code>, <code>gateway_response</code>, <code>webhook_payload</code></td><td></td></tr><tr><td><code>captured_at</code>, <code>failure_reason</code></td><td></td></tr></tbody></table><h3 id="payment-transactions" tabindex="-1"><code>payment_transactions</code> <a class="header-anchor" href="#payment-transactions" aria-label="Permalink to &quot;`payment_transactions`&quot;">‚Äã</a></h3><p>Append-only gateway status events per payment: <code>payment_id</code>, <code>status</code>, <code>amount</code>, <code>error</code>, <code>raw_payload</code>.</p><h2 id="table-dictionary-impersonation" tabindex="-1">Table dictionary (impersonation) <a class="header-anchor" href="#table-dictionary-impersonation" aria-label="Permalink to &quot;Table dictionary (impersonation)&quot;">‚Äã</a></h2><h3 id="impersonation-sessions" tabindex="-1"><code>impersonation_sessions</code> <a class="header-anchor" href="#impersonation-sessions" aria-label="Permalink to &quot;`impersonation_sessions`&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>central_user_id</code></td><td>FK <code>central_users</code> (admin)</td></tr><tr><td><code>tenant_id</code></td><td>FK <code>tenants</code></td></tr><tr><td><code>reason</code></td><td>Required audit text</td></tr><tr><td><code>ip_address</code>, <code>user_agent</code></td><td>Request metadata</td></tr><tr><td><code>started_at</code>, <code>ended_at</code>, <code>duration_seconds</code></td><td>Session window</td></tr></tbody></table><h3 id="system-settings" tabindex="-1"><code>system_settings</code> <a class="header-anchor" href="#system-settings" aria-label="Permalink to &quot;`system_settings`&quot;">‚Äã</a></h3><p>Key/value store for Central Application settings (<code>key</code> unique, <code>value</code>, <code>type</code>, <code>group</code>).</p><p>Groups: <code>general</code>, <code>localization</code>, <code>mail</code>, <code>branding</code>, <code>security</code>, <code>maintenance</code>, <code>billing</code>.</p><p>Sensitive values (<code>mail_password</code>) are encrypted at rest and masked in the admin API. Logo/favicon paths store relative object keys (<code>branding/logos</code>, <code>branding/favicons</code>) on the configured uploads disk (<code>public</code> locally / <code>s3</code> in production).</p><p><code>maintenance_mode</code> gates the <strong>Tenant Application</strong> only ‚Äî never Laravel <code>artisan down</code> for Central.</p><p>Catalog (see <code>App\\Support\\SystemSettingDefinitions</code>):</p><table tabindex="0"><thead><tr><th>Group</th><th>Keys</th></tr></thead><tbody><tr><td>general</td><td><code>app_name</code>, <code>company_name</code>, <code>timezone</code>, <code>locale</code>, <code>currency</code>, <code>registration_enabled</code></td></tr><tr><td>localization</td><td><code>date_format</code>, <code>time_format</code></td></tr><tr><td>mail</td><td><code>mail_driver</code>, <code>mail_host</code>, <code>mail_port</code>, <code>mail_username</code>, <code>mail_password</code>, <code>mail_encryption</code>, <code>mail_from_name</code>, <code>mail_from_address</code></td></tr><tr><td>branding</td><td><code>button_color</code>, <code>support_email</code>, <code>logo_path</code>, <code>favicon_path</code></td></tr><tr><td>security</td><td><code>session_lifetime_minutes</code>, <code>password_min_length</code>, <code>password_require_special</code></td></tr><tr><td>maintenance</td><td><code>maintenance_mode</code>, <code>maintenance_message</code>, <code>maintenance_eta</code></td></tr><tr><td>billing</td><td><code>invoice_prefix</code>, <code>proration_mode</code>, <code>trial_enabled</code>, <code>stripe_enabled</code>, <code>stripe_webhook_configured</code>, <code>default_payment_gateway</code></td></tr></tbody></table><p>Obsolete (removed by migration/seeder): <code>primary_color</code>, <code>queue_connection_display</code>, <code>filesystem_disk</code>, <code>feature_registration</code>, <code>feature_invites</code>, <code>default_plan_id</code>.</p><p>Docs: <a href="/user-guide/central-settings-overview">settings/settings.md</a>.</p><h3 id="tenant-settings" tabindex="-1"><code>tenant_settings</code> <a class="header-anchor" href="#tenant-settings" aria-label="Permalink to &quot;`tenant_settings`&quot;">‚Äã</a></h3><p>Per-workspace overrides of Central defaults (<code>tenant_id</code> + <code>key</code> unique, <code>value</code>, <code>type</code>, <code>group</code>).</p><p>Resolution hierarchy (via <code>TenantSettingService</code>): tenant override ‚Üí tenant profile columns ‚Üí Central <code>system_settings</code> ‚Üí system default.</p><p>Groups: <code>general</code>, <code>branding</code>, <code>mail</code>. Sensitive <code>mail_password</code> encrypted. Branding files under <code>tenants/{uuid}/branding/‚Ä¶</code> on the configured uploads disk.</p><p>Docs: <a href="/user-guide/tenant-settings-overview">settings/tenant-settings.md</a>.</p><h2 id="removed-tables" tabindex="-1">Removed tables <a class="header-anchor" href="#removed-tables" aria-label="Permalink to &quot;Removed tables&quot;">‚Äã</a></h2><p><code>plans</code>, <code>plan_module</code>, <code>plan_feature</code>, <code>plan_limits</code>, <code>limit_definitions</code>, <code>tenant_usage_counters</code>, <code>tenant_subscriptions</code>, <code>subscription_events</code> (replaced by module subscription history), <code>features</code> (removed ‚Äî modules are licensing only; Spatie permissions handle authorization).</p><h2 id="archive-vs-soft-delete" tabindex="-1">Archive vs soft delete <a class="header-anchor" href="#archive-vs-soft-delete" aria-label="Permalink to &quot;Archive vs soft delete&quot;">‚Äã</a></h2><p>Unchanged: <code>archived_at</code> is independent of soft delete.</p>',89)])])}const h=o(c,[["render",s]]);export{m as __pageData,h as default};
